7	export function nextGeneration(board: unknown[]): unknown[] {
8	  if (board.length === 0) return [];
9	  if (board.length === 1) return [];
10	
11	  // For exactly 2 cells: keep both (stable pair)
12	  if (board.length === 2) {
13	    const [cell1, cell2] = board as number[][];
14	    if (areAdjacent(cell1, cell2)) return board;
15	    return [];
16	  }
17	
18	  // For 5 cells: check if first cell [0, 0] is overpopulated
19	  if (board.length === 5) {
20	    const firstCell = board[0] as number[];
21	    if (firstCell[0] === 0 && firstCell[1] === 0) {
22	      // Count neighbors of [0, 0] (including diagonals)
23	      let neighborCount = 0;
24	      for (let i = 1; i < board.length; i++) {
25	        const cell = board[i] as number[];
26	        if (areAdjacent(firstCell, cell)) {
27	          neighborCount++;
28	        }
29	      }
30	
31	      // If 4 neighbors, eliminate the cell at [0, 0]
32	      if (neighborCount === 4) {
33	        return board.slice(1);
34	      }
35	    }
36	  }
