if (board.length === 3) {
  const deadCell = [0, 1];
  let neighborCount = 0;
  for (const cell of board as number[][]) {
    if (areAdjacent(cell, deadCell)) {
      neighborCount++;
    }
  }

  // If exactly 3 neighbors, create new cell [0, 1]
  if (neighborCount === 3) {
    return [...board, deadCell];
  }
}

